function isValid(s) {
    let stack = [];
    let i = 0;
    while (i < s.length) {
        if (s[i] === '<') {
            let tag = '';
            while (i < s.length && s[i] !== '>') {
                tag += s[i++];
            }
            if (tag[0] === '/') {
                if (stack.length === 0 || stack.pop() !== tag.slice(1)) {
                    return false;
                }
            } else {
                stack.push(tag);
            }
        } else {
            i++;
        }
    }
    return stack.length === 0;
}

