class Solution:
    def isValid(self, s: str) -> bool:
        stack = []
        i = 0
        while i < len(s):
            if s[i] == '<':
                tag = ''
                while i < len(s) and s[i] != '>':
                    tag += s[i]
                    i += 1
                if tag[0] == '/':
                    if len(stack) == 0 or stack.pop() != tag[1:]:
                        return False
                else:
                    stack.append(tag)
            else:
                i += 1
        return len(stack) == 0
